// ═══════════════════════════════════════════════════════════════════
//  CORTEX ENRICHMENT — SOAR path
//  Alert observables (src_ip, parent_domain) → routed enrichment
//  → shaped to fill the ticket's enrichment block
// ═══════════════════════════════════════════════════════════════════
const T0 = Date.now();

const CORTEX = 'http://10.10.10.10:9001';
const AUTH   = 'Bearer ' + 'PASTE_FULL_MDR_ADMIN_KEY';  
const TLP    = 2;

const REGISTRY = {
  AbuseIPDB:  { id: '7949e6404f6a75c2c8d2661dbf5656c8' },
  VirusTotal: { id: 'd911cd666346650b3d3f9b99998b0d42' },
  URLhaus:    { id: '2983c453fe359bab2e3e0e67563d47d6' },
  Pulsedive:  { id: 'a1ea4f51edd0e4cc86badab86cafb3ce' },
  GoogleDNS:  { id: '1f039c328b0c7f1434a1c5e741d2e4d6' },
};

const ROUTING = {
  ip:     ['AbuseIPDB', 'VirusTotal', 'Pulsedive'],
  domain: ['VirusTotal', 'URLhaus', 'Pulsedive', 'GoogleDNS'],
};

const CONCURRENCY             = 3;
const PER_ANALYZER_TIMEOUT_MS = 40000;
const POLL_SCHEDULE_MS        = [800, 1200, 1500, 2000, 2500, 3000];
const POLL_FALLBACK_MS        = 3500;

const http  = this.helpers.httpRequest.bind(this);
const sleep = (ms) => new Promise(r => setTimeout(r, ms));
const jsonHeaders = { Authorization: AUTH, 'Content-Type': 'application/json', Accept: 'application/json' };

const LEVEL_RANK = { info: 0, safe: 1, suspicious: 2, malicious: 3 };
const RANK_LEVEL = ['info', 'safe', 'suspicious', 'malicious'];

// Some analyzers colour informational metrics with a severity level:
// VT "43 resolution(s)", GoogleDNS record counts, EmailRep references.
// Those are context, not verdicts — ranking them turns every lookup malicious.
const NON_VERDICT = [/resolution\(s\)/i, /record/i, /reference/i];
const bearsVerdict = (t) => {
  const v = String(t.val !== undefined ? t.val : (t.value !== undefined ? t.value : ''));
  return !NON_VERDICT.some(re => re.test(v));
};

async function jobStatus(id) {
  const r = await http({ method: 'GET', url: `${CORTEX}/api/job/${id}`, headers: jsonHeaders, json: true });
  return r.status;
}

async function jobReport(id) {
  const r = await http({ method: 'GET', url: `${CORTEX}/api/job/${id}/report`, headers: jsonHeaders, json: true });
  let rep = r.report || {};
  if (typeof rep === 'string') rep = JSON.parse(rep);
  return rep;
}

async function poll(id, budgetMs) {
  const start = Date.now();
  let i = 0;
  while (Date.now() - start < budgetMs) {
    try {
      const s = await jobStatus(id);
      if (s === 'Success' || s === 'Failure') return s;
    } catch (e) { /* transient */ }
    await sleep(POLL_SCHEDULE_MS[i] ?? POLL_FALLBACK_MS);
    i++;
  }
  return 'Timeout';
}

// ── observables from the alert ─────────────────────────────────────
const d = $('allowlist').first().json;
const srcIp  = (d.soar_decision && d.soar_decision.src_ip) || (d.data && d.data.src_ip) || null;
const domain = d.parent_domain || (d.data && d.data.parent_domain) || null;

// RFC1918 / loopback: no external reputation source knows these — asking is noise
const isPrivate = (ip) => /^(10\.|127\.|192\.168\.|172\.(1[6-9]|2\d|3[01])\.)/.test(String(ip || ''));

const OBSERVABLES = [];
const skipped = [];
if (srcIp) {
  if (isPrivate(srcIp)) skipped.push({ observable: srcIp, reason: 'internal address — no external reputation applies' });
  else OBSERVABLES.push({ dataType: 'ip', data: srcIp });
}
if (domain) OBSERVABLES.push({ dataType: 'domain', data: domain });

// ── plan ───────────────────────────────────────────────────────────
const tasks = [];
for (const obs of OBSERVABLES) {
  for (const az of (ROUTING[obs.dataType] || [])) {
    if (REGISTRY[az]) tasks.push({ azName: az, obs });
  }
}

// ── enrich one observable with one analyzer (isolated) ─────────────
async function enrichOne(azName, obs) {
  const base = { analyzer: azName, obs: obs.data, dataType: obs.dataType, taxonomies: [], rank: 0 };
  try {
    const run = await http({
      method: 'POST',
      url: `${CORTEX}/api/analyzer/${REGISTRY[azName].id}/run`,
      headers: jsonHeaders,
      body: { dataType: obs.dataType, data: obs.data, tlp: TLP },
      json: true,
    });
    const st = await poll(run.id, PER_ANALYZER_TIMEOUT_MS);
    if (st !== 'Success') return { ...base, status: st };

    const rep = await jobReport(run.id);
    const tax = (rep.summary && rep.summary.taxonomies) || [];

    let rank = 0;
    for (const t of tax) {
      if (bearsVerdict(t)) rank = Math.max(rank, LEVEL_RANK[t.level] ?? 0);
    }

    return {
      ...base,
      status: 'Success',
      rank,
      taxonomies: tax.map(t => ({ level: t.level, ns: t.namespace, pred: t.predicate, val: t.value })),
    };
  } catch (e) {
    return { ...base, status: 'Error', error: String((e && e.message) || e).slice(0, 200) };
  }
}

// ── bounded-parallel execution ─────────────────────────────────────
const results = [];
for (let i = 0; i < tasks.length; i += CONCURRENCY) {
  const batch   = tasks.slice(i, i + CONCURRENCY);
  const settled = await Promise.allSettled(batch.map(t => enrichOne(t.azName, t.obs)));
  for (let j = 0; j < settled.length; j++) {
    const s = settled[j];
    results.push(
      s.status === 'fulfilled'
        ? s.value
        : {
            analyzer: batch[j].azName, obs: batch[j].obs.data, dataType: batch[j].obs.dataType,
            status: 'Error', error: String(s.reason), taxonomies: [], rank: 0,
          }
    );
  }
}

// ── roll up ────────────────────────────────────────────────────────
const byObservable = {};
const reasons = [];
let worst = 0, ran = 0, failed = 0;

for (const r of results) {
  if (r.status === 'Success') ran++; else failed++;
  worst = Math.max(worst, r.rank);

  for (const t of r.taxonomies) {
    if (bearsVerdict(t) && (LEVEL_RANK[t.level] ?? 0) >= 2) {
      reasons.push(`${r.obs} → ${t.ns}:${t.pred}=${t.val}`);
    }
  }

  const o = byObservable[r.obs] = byObservable[r.obs] || { dataType: r.dataType, verdict: 'info', analyzers: {} };
  o.analyzers[r.analyzer] = {
    status: r.status,
    level: RANK_LEVEL[r.rank],
    taxonomies: r.taxonomies,
    ...(r.error ? { error: r.error } : {}),
  };
  o.verdict = RANK_LEVEL[Math.max(LEVEL_RANK[o.verdict] ?? 0, r.rank)];
}

// ── headline fields for the ticket ─────────────────────────────────
const findTax = (obsVal, ns, predMatch) => {
  const o = byObservable[obsVal];
  if (!o) return null;
  for (const az of Object.values(o.analyzers)) {
    for (const t of az.taxonomies) {
      if (t.ns === ns && (!predMatch || t.pred === predMatch)) return t;
    }
  }
  return null;
};

const vtTax  = domain ? findTax(domain, 'VT', 'GetReport') : null;
const vtHits = vtTax && /^\d+\/\d+$/.test(String(vtTax.val)) ? String(vtTax.val) : null;
const abTax  = (srcIp && !isPrivate(srcIp)) ? findTax(srcIp, 'AbuseIPDB', 'Score') : null;

return [{
  json: {
    ...d,
    cortex: {
      status: tasks.length ? 'completed' : 'skipped',
      verdict: RANK_LEVEL[worst],
      verdict_reason: [...new Set(reasons)],
      virustotal: {
        domain: domain || null,
        verdict: domain ? ((byObservable[domain] && byObservable[domain].verdict) || 'unknown') : null,
        detections: vtHits,
        checked: !!vtTax,
      },
      abuseipdb: {
        ip: srcIp || null,
        score: abTax ? abTax.val : null,
        checked: !!abTax,
        note: (srcIp && isPrivate(srcIp)) ? 'internal address — not submitted to external reputation' : undefined,
      },
      observables: byObservable,
      skipped,
      analyzers_run: ran,
      analyzers_failed: failed,
      duration_ms: Date.now() - T0,
    },
  },
}];

// ============================================================
//  SOC Investigation Ticket Builder
//  Classifies the detection by ATT&CK tactic, then derives the
//  priority, the investigation plan and the playbook from it.
//  Every alert produces a ticket — containment status is a field,
//  not a precondition.
// ============================================================
const d   = $('allowlist').first().json;
const enr = (() => { try { return ($('Cortex enrichment').first().json || {}).cortex || null; } catch (e) { return null; } })();

const now = new Date();
const pad = n => String(n).padStart(2, "0");

// ---- MITRE technique → tactic + investigation profile ----
const TECHNIQUES = {
  'T1003.001': { name: 'LSASS Memory Dump',              tactic: 'Credential Access',  weight: 3 },
  'T1027':     { name: 'Obfuscated Files or Information',tactic: 'Defense Evasion',    weight: 2 },
  'T1046':     { name: 'Network Service Discovery',      tactic: 'Discovery',          weight: 1 },
  'T1048':     { name: 'Exfiltration Over Alt Protocol', tactic: 'Exfiltration',       weight: 3 },
  'T1059.001': { name: 'PowerShell Execution',           tactic: 'Execution',          weight: 2 },
  'T1071.004': { name: 'DNS Application Layer Protocol', tactic: 'Command and Control', weight: 3 },
  'T1098':     { name: 'Account Manipulation',           tactic: 'Persistence',        weight: 2 },
  'T1105':     { name: 'Ingress Tool Transfer',          tactic: 'Command and Control', weight: 2 },
  'T1539':     { name: 'Steal Web Session Cookie',       tactic: 'Credential Access',  weight: 3 },
  'T1543.002': { name: 'Create or Modify System Service',tactic: 'Persistence',        weight: 2 },
  'T1548.003': { name: 'Sudo and Sudo Caching Abuse',    tactic: 'Privilege Escalation', weight: 2 },
  'T1555.003': { name: 'Credentials from Web Browsers',  tactic: 'Credential Access',  weight: 3 },
  'T1562.001': { name: 'Disable or Modify Tools',        tactic: 'Defense Evasion',    weight: 3 },
  'T1562.004': { name: 'Disable or Modify System Firewall', tactic: 'Defense Evasion', weight: 3 },
  'T1610':     { name: 'Deploy Container',               tactic: 'Execution',          weight: 2 },
  'T1611':     { name: 'Escape to Host',                 tactic: 'Privilege Escalation', weight: 3 },
};

// ---- per-tactic investigation plan (what an L1 actually does) ----
const PLAYBOOKS = {
  'Credential Access': {
    focus: 'Determine whether credentials were actually obtained, and which identities are now untrusted.',
    tasks: [
      'Identify the accessing process and its full parent chain',
      'Establish whether the access succeeded or was blocked by protections',
      'Locate any dump/output artefact written to disk and preserve it',
      'List every account whose credentials were resident on the host',
      'Hunt for the same technique across other endpoints',
      'Check for authentication using the exposed accounts after the event',
    ],
    containment: 'Force password reset for exposed accounts and invalidate active sessions.',
  },
  'Command and Control': {
    focus: 'Confirm the channel is adversary-controlled and identify what the host sent out.',
    tasks: [
      'Review the beaconing pattern: interval, jitter, and total volume',
      'Resolve the destination and review its registration age and hosting',
      'Correlate with the process that initiated the connections',
      'Search for the same destination across all other hosts',
      'Assess whether data left the environment over this channel',
      'Verify containment stopped the traffic',
    ],
    containment: 'Isolate the host and block the destination at the perimeter.',
  },
  'Exfiltration': {
    focus: 'Establish what data left, over which channel, and to whom.',
    tasks: [
      'Quantify the volume and duration of the outbound activity',
      'Identify the source process and the files it accessed',
      'Determine the destination owner and infrastructure',
      'Classify the sensitivity of the data involved',
      'Preserve evidence for potential disclosure obligations',
    ],
    containment: 'Cut the channel and preserve evidence before remediation.',
  },
  'Defense Evasion': {
    focus: 'Treat as an active intrusion — an adversary disabling controls is preparing further action.',
    tasks: [
      'Identify what security control was disabled or modified, and by which account',
      'Establish whether the change was authorised (change records, admin activity)',
      'Reconstruct activity in the window while the control was down',
      'Re-enable the control and confirm it is reporting',
      'Hunt for follow-on activity that the gap may have hidden',
    ],
    containment: 'Restore the control and treat the blind window as unmonitored.',
  },
  'Privilege Escalation': {
    focus: 'Determine whether elevated access was obtained and what it was used for.',
    tasks: [
      'Identify the escalation mechanism and whether it succeeded',
      'Enumerate actions taken under elevated context afterwards',
      'Check for new accounts, services or scheduled tasks created',
      'Assess whether the mechanism affects other hosts',
    ],
    containment: 'Revoke elevated access and remediate the escalation path.',
  },
  'Persistence': {
    focus: 'Find every foothold — persistence is rarely established only once.',
    tasks: [
      'Document the persistence mechanism and its exact configuration',
      'Identify the account and process that created it',
      'Enumerate other persistence locations on the host',
      'Establish the original access vector that preceded it',
      'Remove all footholds before restoring the host',
    ],
    containment: 'Remove every mechanism found — partial removal invites re-entry.',
  },
  'Execution': {
    focus: 'Understand what ran, how it was launched, and what it did.',
    tasks: [
      'Recover the full command line and decode any obfuscation',
      'Trace the parent process to the original delivery vector',
      'Identify files written or network connections opened',
      'Determine whether execution is expected for this host role',
    ],
    containment: 'Terminate the process tree and quarantine artefacts.',
  },
  'Discovery': {
    focus: 'Usually reconnaissance preceding a further move — establish scope and intent.',
    tasks: [
      'Determine what was enumerated and how broadly',
      'Identify whether the source is a legitimate scanning tool',
      'Look for follow-on activity against discovered targets',
      'Confirm whether the host is authorised to scan',
    ],
    containment: 'Usually monitoring rather than blocking, unless the source is untrusted.',
  },
};

const GENERIC_PLAYBOOK = {
  focus: 'Establish what happened, whether it is expected, and whether it spread.',
  tasks: [
    'Verify the source host identity and its owner',
    'Determine whether the activity is expected for this host',
    'Review enrichment verdicts on the observables',
    'Pivot: search other hosts for the same pattern',
    'Escalate to L2 or resolve with justification',
  ],
  containment: 'Assess case by case.',
};

// ---- classify ----
const mitreArr = Array.isArray(d.mitre) ? d.mitre : (d.mitre ? [d.mitre] : []);
const known    = mitreArr.map(t => TECHNIQUES[t]).filter(Boolean);
const primary  = known.sort((a, b) => b.weight - a.weight)[0] || null;
const tactic   = primary ? primary.tactic : 'Uncategorised';
const playbook = PLAYBOOKS[tactic] || GENERIC_PLAYBOOK;

// ---- severity: rule level, raised by tactic weight and threat intel ----
const lvl = d.rule_level || 0;
let base = lvl >= 13 ? 3 : lvl >= 10 ? 2 : lvl >= 7 ? 1 : 0;
if (primary && primary.weight === 3) base = Math.min(3, base + 1);
if (enr && enr.verdict === 'malicious') base = 3;
else if (enr && enr.verdict === 'suspicious') base = Math.min(3, base + 1);

const SEV = [
  { name: 'Low',      tlp: 'WHITE', sla: 72 },
  { name: 'Medium',   tlp: 'GREEN', sla: 24 },
  { name: 'High',     tlp: 'AMBER', sla: 4  },
  { name: 'Critical', tlp: 'RED',   sla: 1  },
][base];

const slaDue = new Date(now.getTime() + SEV.sla * 3600 * 1000);

// ---- identifiers ----
const dateKey   = `${now.getUTCFullYear()}${pad(now.getUTCMonth()+1)}${pad(now.getUTCDate())}`;
const timeKey   = `${pad(now.getUTCHours())}${pad(now.getUTCMinutes())}${pad(now.getUTCSeconds())}`;
const ticketKey = `SOC-${dateKey}-${timeKey}`;

// ---- fields ----
const srcIp  = (d.soar_decision && d.soar_decision.src_ip) || (d.data && d.data.src_ip) || 'unknown';
const dstDom = d.parent_domain || (d.data && d.data.parent_domain) || null;
const qCount = d.query_count || (d.data && d.data.query_count) || null;
const action = (d.soar_decision && d.soar_decision.action) || 'none';
const reason = (d.soar_decision && d.soar_decision.reason) || 'n/a';

const contained = action === 'allow_block';
const CONTAINMENT_NOTE = {
  allow_block: `Host ${srcIp} isolated automatically (added to pfSense soar_blocklist).`,
  refused:     `No automated containment — ${srcIp} is protected infrastructure. Manual assessment required before any action.`,
  skip:        `No automated containment — the alert carried no source address to act on.`,
  none:        `No containment attempted.`,
};
const actionText = CONTAINMENT_NOTE[action] || CONTAINMENT_NOTE.none;

// ---- threat intelligence summary line ----
const tiLine = !enr ? 'Enrichment unavailable.'
  : enr.status === 'skipped' ? 'No external observables to enrich.'
  : enr.verdict === 'malicious' ? `Threat intelligence flags an observable as malicious: ${(enr.verdict_reason || []).join('; ')}`
  : enr.verdict === 'suspicious' ? `Threat intelligence raised suspicion: ${(enr.verdict_reason || []).join('; ')}`
  : 'No adverse threat-intelligence findings on the observables.';

// ---- description ----
const description = `
## Assessment
**${tactic}** — ${primary ? primary.name : (d.rule_desc || 'uncategorised activity')}.
${playbook.focus}

Containment: **${contained ? 'APPLIED' : 'NOT APPLIED'}**. ${tiLine}

## Detection
| Field | Value |
|---|---|
| Rule | ${d.rule_id} — ${d.rule_desc} |
| Wazuh level | ${lvl} |
| Tactic | ${tactic} |
| Technique | ${mitreArr.join(', ') || 'n/a'} |
| Source host | \`${srcIp}\` |
${dstDom ? `| Destination | \`${dstDom}\` |\n` : ''}${qCount ? `| Observed count | ${qCount} |\n` : ''}| Detected | ${d.timestamp || now.toISOString()} |

## Response taken
${actionText}

## Recommended containment for this tactic
${playbook.containment}
`.trim();

// ---- observables ----
const observables = [
  { type: 'ip', value: srcIp, role: 'source', ioc: false, note: 'internal endpoint' },
];
if (dstDom) {
  observables.push({
    type: 'domain', value: dstDom, role: 'destination',
    ioc: !!(enr && (enr.verdict === 'malicious' || enr.verdict === 'suspicious')),
    note: enr && enr.virustotal && enr.virustotal.detections
      ? `VirusTotal: ${enr.virustotal.detections}` : 'no enrichment data',
  });
}

// ---- ticket ----
const ticket = {
  ticket_key:  ticketKey,
  summary:     `[${SEV.name}] ${tactic}: ${primary ? primary.name : (d.rule_desc || 'Security alert')} on ${srcIp}`,
  type:        'Security Incident',
  status:      'Open',
  priority:    SEV.name,
  tlp:         SEV.tlp,
  created_utc: now.toISOString(),
  reporter:    'Wazuh SOAR (automated)',
  assignee:    'unassigned',
  sla_due_utc: slaDue.toISOString(),
  sla_hours:   SEV.sla,

  classification: {
    tactic,
    techniques: mitreArr,
    technique_names: known.map(k => k.name),
    confidence: known.length ? 'mapped' : 'unmapped — rule carries no known technique',
  },

  labels: [
    ...mitreArr,
    tactic.toLowerCase().replace(/\s+/g, '-'),
    SEV.name.toLowerCase(),
    contained ? 'auto-contained' : 'not-contained',
    ...(enr && enr.verdict && enr.verdict !== 'info' ? [`ti-${enr.verdict}`] : []),
  ],

  description,
  observables,

  timeline: [
    { time: d.timestamp || now.toISOString(), event: `Detection: ${d.rule_id} — ${d.rule_desc}` },
    { time: now.toISOString(), event: `Classified as ${tactic}` },
    { time: now.toISOString(), event: `SOAR decision: ${action} (${reason})` },
    ...(enr && enr.status === 'completed'
      ? [{ time: now.toISOString(), event: `Enrichment complete — verdict ${enr.verdict}` }] : []),
  ],

  automated_response: {
    decision: action,
    reason,
    action_taken: actionText,
    contained,
    allowlist_protected: action === 'refused' && reason === 'allowlist',
  },

  enrichment: enr ? {
    status: enr.status,
    verdict: enr.verdict,
    reasons: enr.verdict_reason,
    virustotal: enr.virustotal,
    abuseipdb: enr.abuseipdb,
    observables: enr.observables,
    skipped: enr.skipped,
    analyzers: { run: enr.analyzers_run, failed: enr.analyzers_failed },
    took_ms: enr.duration_ms,
  } : { status: 'unavailable', note: 'No enrichment ran for this alert' },

investigation_tasks: (
    action === 'refused'
      ? ['Assess impact on the protected asset before any containment decision',
         'Escalate to L2 — containment on infrastructure requires authorisation',
         ...playbook.tasks]
      : action === 'skip'
        ? ['Identify the affected host from the raw alert — no source address was present',
           ...playbook.tasks]
        : playbook.tasks
  ).map((t, i) => ({ id: i + 1, task: t, status: 'todo', owner: 'L1' })),

  work_notes: [],
  disposition: 'PENDING',
  resolution: '',

  playbook: `PICERL — ${tactic}: Prepare → Identify → Contain (${contained ? 'automated' : 'manual required'}) → Eradicate → Recover → Lessons`,
  runbook_url: 'https://github.com/AJahmadcyber/homelab-mdr',
};

return [{ json: ticket }];

// Extract source IP from the Wazuh alert + allowlist safety check
const alert = $('Webhook').first().json.body;

// pull src_ip from common Wazuh alert locations
const srcIp = alert?.data?.src_ip 
           || alert?.data?.srcip 
           || alert?.data?.win?.eventdata?.sourceIp 
           || null;

// --- SAFETY: infrastructure allowlist (NEVER block these) ---
const ALLOWLIST = {
  "10.10.10.1":  "pfSense gateway",
  "10.10.10.10": "siem (SIEM + n8n)",
  "10.10.10.2":  "ThinkPad host"
};

let decision;
if (!srcIp) {
  decision = { action: "skip", reason: "no_src_ip", src_ip: null };
} else if (ALLOWLIST[srcIp]) {
  decision = { action: "refused", reason: "allowlist", src_ip: srcIp, detail: ALLOWLIST[srcIp] };
} else {
  decision = { action: "allow_block", reason: "passed_safety", src_ip: srcIp };
}

return [{
  json: {
    ...alert,
    soar_decision: decision,
    rule_id: alert?.rule?.id,
    rule_level: alert?.rule?.level,
    rule_desc: alert?.rule?.description,
    mitre: alert?.rule?.mitre?.id
  }
}];

// Maps the SOC ticket to a TheHive v1 Alert payload
const t = $('SOC Investigation Ticket').first().json;
const d = $('allowlist').first().json;

const SEV_MAP = { low: 1, medium: 2, high: 3, critical: 4 };
const severity = SEV_MAP[String(t.priority || '').toLowerCase()] || 2;

const TLP_MAP = { clear: 0, white: 0, green: 1, amber: 2, 'amber+strict': 3, red: 4 };
let tlp = 2;
if (typeof t.tlp === 'number') tlp = t.tlp;
else if (t.tlp) { const k = String(t.tlp).toLowerCase().replace('tlp:', ''); if (k in TLP_MAP) tlp = TLP_MAP[k]; }

const checklist = (t.investigation_tasks || []).map(x => `- [ ] ${x.task}`).join('\n');
const timeline  = (t.timeline  || []).map(ev => `- ${ev.time} — ${ev.event}`).join('\n');
const e = t.enrichment || {};

const description = [
  t.description || '',
  `**Playbook:** ${t.playbook}`,
  `**SLA:** ${t.sla_hours}h — due ${t.sla_due_utc}`,
  `### Classification`,
  `Tactic: **${t.classification.tactic}** | Techniques: ${(t.classification.techniques || []).join(', ') || '—'} (${t.classification.confidence})`,
  `### Automated response`,
  `Decision: **${t.automated_response.decision}** (${t.automated_response.reason}) — ${t.automated_response.action_taken} | contained: ${t.automated_response.contained}`,
  `### Enrichment`,
  `Status: ${e.status} | Verdict: **${e.verdict || 'n/a'}**${e.reasons ? ' — ' + [].concat(e.reasons).join('; ') : ''}`,
  `### L1 investigation checklist`,
  checklist,
  `### Timeline`,
  timeline,
].join('\n\n');

const observables = (t.observables || [])
  .filter(o => o && o.value)
  .map(o => ({
    dataType: o.type,
    data: String(o.value),
    message: `${o.role || ''}${o.note ? ' — ' + o.note : ''}`,
    ioc: !!o.ioc,
    tags: o.role ? ['role:' + o.role] : [],
  }));

return [{ json: {
  type: 'soar-triage',
  source: 'wazuh-soar',
  sourceRef: t.ticket_key,
  title: t.summary,
  description,
  severity,
  tlp,
  date: Date.parse(t.created_utc) || Date.now(),
  tags: [...(t.labels || []), 'rule-' + (d.rule_id || 'unknown')],
  observables,
} }];
